  async _runFetch(query, page) {
    this.loading = true;
    this._emit();
    let result;
    try {
      result = await this.fetchUsers(query, page, this.pageSize);
    } catch (err) {
      this.loading = false;
      this._emit();
      throw err;
    }

    // Stale checking logic using a generation counter
    if (this.query !== query || this.page !== page) {
      this.loading = false; // Do not affect loading state
      this._emit();
      return; // Ignore this stale request
    }

    this.users = result.users;
    this.total = result.total;
    this.loading = false;
    this._emit();
  }

